38 |   noun_to_verb_ratio: number;
39 | }
40 | 
41 | /** Mirrors StylisticFeatures in api_contract.yaml — StyleProfile.stylistic. */
42 | export interface StylisticFeatures {
43 |   /** Relative frequency per punctuation mark. */
44 |   punct_distribution: Record<string, number>;
45 |   /** Relative frequency per POS tag (spaCy labels). */
46 |   pos_distribution: Record<string, number>;
47 |   /** Fraction of sentences that are dialogue (heuristic). Native range [0, 1]. */
48 |   dialogue_ratio: number;
49 |   /** Fraction of sentences with first-person pronouns (heuristic). Native range [0, 1]. */
50 |   first_person_ratio: number;
