Contents of file frontend/src/components/GenerateStudio.tsx:

1 | "use client";
2 | 
3 | import { useCallback, useRef, useState } from "react";
4 | 
5 | import { PromptComposer } from "@/components/PromptComposer";
6 | import { SideBySideOutput } from "@/components/SideBySideOutput";
7 | import type { GenerationState } from "@/components/AuthorColumn";
8 | import { generateText } from "@/lib/api";
9 | import { en } from "@/lib/i18n/en";
10 | import type { AuthorCardData } from "@/lib/types";
11 | 
12 | interface GenerateStudioProps {
13 |   author: AuthorCardData;
14 | }
15 | 
16 | /**
17 |  * Generation studio client component — owns prompt state and both column
18 |  * GenerationStates. Passes real response data to SideBySideOutput; never
19 |  * fakes the contrast (design-system §8).
20 |  *
21 |  * The parent page (server component) owns the page header and data-voice.
22 |  * This component starts in an "idle" visual state before the first generation.
23 |  */
24 | export function GenerateStudio({ author }: GenerateStudioProps) {
25 |   const [prompt, setPrompt] = useState("");
26 |   const [isSubmitting, setIsSubmitting] = useState(false);
27 |   const [vanillaState, setVanillaState] = useState<GenerationState>({
28 |     status: "loading",
29 |   });
30 |   const [autoriaState, setAutoriaState] = useState<GenerationState>({
31 |     status: "loading",
32 |   });
33 |   const [hasGenerated, setHasGenerated] = useState(false);
34 | 
35 |   /**
36 |    * Distinctive terms from the StyleProfile — optional enhancement.
37 |    * Not fetched here; could be passed in from a parent that already has
38 |    * the StyleProfile loaded. Kept as a future prop without blocking
39 |    * generation (design-system §7, Deliverable 6).
40 |    */
41 |   const [distinctiveTerms] = useState<readonly string[]>([]);
42 | 
43 |   // Keep last prompt so onRetry can re-run it without re-reading stale state.
44 |   const lastPromptRef = useRef<string>("");
45 | 
46 |   const runGeneration = useCallback(
47 |     async (promptText: string) => {
48 |       lastPromptRef.current = promptText;
49 |       setIsSubmitting(true);
50 |       setHasGenerated(true);
51 |       setVanillaState({ status: "loading" });
52 |       setAutoriaState({ status: "loading" });
53 | 
54 |       try {
55 |         const response = await generateText(author.id, promptText);
56 |         setVanillaState({ status: "success", output: response.vanilla });
57 |         setAutoriaState({ status: "success", output: response.autoria });
58 |       } catch (err: unknown) {
59 |         const isAbort = err instanceof Error && err.name === "AbortError";
60 |         const nextState: GenerationState = isAbort
61 |           ? { status: "timeout" }
62 |           : { status: "error" };
63 |         setVanillaState(nextState);
64 |         setAutoriaState(nextState);
65 |       } finally {
66 |         setIsSubmitting(false);
67 |       }
68 |     },
69 |     [author.id],
70 |   );
71 | 
72 |   const handleSubmit = useCallback(() => {
73 |     if (prompt.trim().length === 0 || isSubmitting) return;
74 |     void runGeneration(prompt);
75 |   }, [prompt, isSubmitting, runGeneration]);
76 | 
77 |   const handleRetry = useCallback(() => {
78 |     if (isSubmitting) return;
79 |     void runGeneration(lastPromptRef.current);
80 |   }, [isSubmitting, runGeneration]);
81 | 
82 |   return (
83 |     <div className="flex flex-col gap-8">
84 |       {/* ── Section label ── */}
85 |       <p className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
86 |         {en.generate.sectionTitle}
87 |       </p>
88 | 
89 |       {/* ── Prompt composer ── */}
90 |       <section aria-label={en.generate.promptLabel}>
91 |         <PromptComposer
92 |           prompt={prompt}
93 |           isSubmitting={isSubmitting}
94 |           onPromptChange={setPrompt}
95 |           onSubmit={handleSubmit}
96 |         />
97 |       </section>
98 | 
99 |       {/* ── Side-by-side output ── */}
100 |       <section aria-label={en.generate.outputSectionLabel}>
101 |         {hasGenerated ? (
102 |           <SideBySideOutput
103 |             authorId={author.id}
104 |             authorName={author.name}
105 |             vanilla={vanillaState}
106 |             autoria={autoriaState}
107 |             distinctiveTerms={distinctiveTerms}
108 |             onRetry={handleRetry}
109 |           />
110 |         ) : (
111 |           <IdleState />
112 |         )}
113 |       </section>
114 |     </div>
115 |   );
116 | }
117 | 
118 | /**
119 |  * Placeholder shown before the first generation. Replaced by SideBySideOutput
120 |  * as soon as Generate is pressed for the first time.
121 |  */
122 | function IdleState() {
123 |   return (
124 |     <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
125 |       {/* Instruction exposed once to assistive tech; the two cards below are
126 |           decorative placeholders (aria-hidden) to avoid a double announcement. */}
127 |       <p className="sr-only">{en.generate.idleBody}</p>
128 |       <IdleColumn />
129 |       <IdleColumn />
130 |     </div>
131 |   );
132 | }
133 | 
134 | function IdleColumn() {
135 |   return (
136 |     <div
137 |       className="flex min-h-[220px] flex-col items-center justify-center gap-3 rounded-xl border border-dashed border-border bg-card px-6 py-10 text-center shadow-paper-sm"
138 |       aria-hidden="true"
139 |     >
140 |       <p className="text-sm font-medium text-muted-foreground">
141 |         {en.generate.idleHeading}
142 |       </p>
143 |       <p className="max-w-[36ch] text-xs text-muted-foreground/70">
144 |         {en.generate.idleBody}
145 |       </p>
146 |     </div>
147 |   );
148 | }
