Contents of file frontend/src/components/StyleDnaPanel.tsx:

1 | "use client";
2 | 
3 | import { useEffect, useRef, useState } from "react";
4 | import { ChevronDown, Feather, TriangleAlert } from "lucide-react";
5 | 
6 | import { getStyleProfile, NotFoundError } from "@/lib/api";
7 | import { listAuthors } from "@/lib/api";
8 | import { FIXTURE_STYLE_PROFILES } from "@/lib/fixtures/style-profiles";
9 | import { en } from "@/lib/i18n/en";
10 | import type { StyleProfile } from "@/lib/types";
11 | import { cn } from "@/lib/utils";
12 | 
13 | import { Button } from "@/components/ui/button";
14 | import { Card, CardContent } from "@/components/ui/card";
15 | import { CorpusMetricChips } from "@/components/MetricChip";
16 | import { EmptyState } from "@/components/EmptyState";
17 | import { StyleRadarChart } from "@/components/StyleRadarChart";
18 | import { StyleScatter2D } from "@/components/StyleScatter2D";
19 | import type { ScatterAuthorPoint } from "@/components/StyleScatter2D";
20 | 
21 | // ---------------------------------------------------------------------------
22 | // Timeout guard: after 10 s without a resolved profile → transition to error
23 | // ---------------------------------------------------------------------------
24 | const FETCH_TIMEOUT_MS = 10_000;
25 | 
26 | // ---------------------------------------------------------------------------
27 | // Panel state (discriminated union — no infinite spinner possible)
28 | // ---------------------------------------------------------------------------
29 | type PanelState =
30 |   | { status: "loading" }
31 |   | { status: "empty" }
32 |   | { status: "error"; message: string }
33 |   | {
34 |       status: "ready";
35 |       profile: StyleProfile;
36 |       scatterPoints: ScatterAuthorPoint[];
37 |     };
38 | 
39 | interface StyleDnaPanelProps {
40 |   /** The author whose style profile to load and display as the selected point. */
41 |   authorId: string;
42 |   /** Display name — used only for the scatter label; fetch is by authorId. */
43 |   authorName: string;
44 | }
45 | 
46 | /**
47 |  * The Style DNA panel: collapsible wrapper that owns all fetch states for the
48 |  * selected author's StyleProfile and the comparison scatter set.
49 |  *
50 |  * States:
51 |  *  • loading — pulsing skeleton + status text + 10 s timeout guard
52 |  *  • empty   — 404 / has_style_profile:false → neutral EmptyState (not an error)
53 |  *  • error   — network/5xx → message + Retry
54 |  *  • ready   — MetricChips + Radar + Scatter, fade-rise reveal
55 |  *
56 |  * Design-system.md §7 inventory: StyleDnaPanel, Sprint 1.
57 |  */
58 | export function StyleDnaPanel({ authorId, authorName }: StyleDnaPanelProps) {
59 |   const [panelState, setPanelState] = useState<PanelState>({
60 |     status: "loading",
61 |   });
62 |   const [expanded, setExpanded] = useState(true);
63 |   const contentId = `style-dna-content-${authorId}`;
64 |   const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
65 | 
66 |   // retryCounter lets the Retry button re-run the same effect
67 |   const [retryCount, setRetryCount] = useState(0);
68 |   const handleRetry = () => setRetryCount((c) => c + 1);
69 | 
70 |   useEffect(() => {
71 |     let cancelled = false;
72 | 
73 |     async function run() {
74 |       setPanelState({ status: "loading" });
75 | 
76 |       // Timeout guard: after FETCH_TIMEOUT_MS with no result, show error
77 |       timeoutRef.current = setTimeout(() => {
78 |         if (!cancelled) {
79 |           setPanelState({ status: "error", message: en.styleDna.error });
80 |         }
81 |       }, FETCH_TIMEOUT_MS);
82 | 
83 |       try {
84 |         const profile = await fetchProfileWithFallback(authorId);
85 |         if (cancelled) return;
86 |         if (timeoutRef.current) clearTimeout(timeoutRef.current);
87 | 
88 |         const scatterPoints = await buildScatterPoints(
89 |           authorId,
90 |           authorName,
91 |           profile,
92 |         );
93 |         if (cancelled) return;
94 | 
95 |         setPanelState({ status: "ready", profile, scatterPoints });
96 |       } catch (err) {
97 |         if (cancelled) return;
98 |         if (timeoutRef.current) clearTimeout(timeoutRef.current);
99 |         if (err instanceof NotFoundError) {
100 |           setPanelState({ status: "empty" });
101 |         } else {
102 |           setPanelState({ status: "error", message: en.styleDna.error });
103 |         }
104 |       }
105 |     }
106 | 
107 |     void run();
108 | 
109 |     return () => {
110 |       cancelled = true;
111 |       if (timeoutRef.current) clearTimeout(timeoutRef.current);
112 |     };
113 |   }, [authorId, authorName, retryCount]);
114 | 
115 |   return (
116 |     <section
117 |       aria-label={en.styleDna.sectionTitle}
118 |       className="flex flex-col gap-3"
119 |     >
120 |       {/* Collapsible header */}
121 |       <div className="flex items-center justify-between">
122 |         <h2 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
123 |           {en.styleDna.sectionTitle}
124 |         </h2>
125 |         <button
126 |           type="button"
127 |           aria-expanded={expanded}
128 |           aria-controls={contentId}
129 |           aria-label={en.styleDna.collapseToggle}
130 |           onClick={() => setExpanded((v) => !v)}
131 |           className="flex items-center justify-center rounded p-1 text-muted-foreground transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
132 |         >
133 |           <ChevronDown
134 |             className={cn(
135 |               "size-4 transition-transform duration-200",
136 |               expanded ? "rotate-0" : "-rotate-90",
137 |             )}
138 |             aria-hidden="true"
139 |           />
140 |         </button>
141 |       </div>
142 | 
143 |       {/* Panel content — conditionally hidden (design-system §5: no height animation) */}
144 |       <div id={contentId} hidden={!expanded}>
145 |         {panelState.status === "loading" && <LoadingSkeleton />}
146 | 
147 |         {panelState.status === "empty" && (
148 |           <EmptyState
149 |             icon={<Feather className="size-5" />}
150 |             title={en.styleDna.empty}
151 |             body={en.styleDna.emptyBody}
152 |           />
153 |         )}
154 | 
155 |         {panelState.status === "error" && (
156 |           <ErrorNotice message={panelState.message} onRetry={handleRetry} />
157 |         )}
158 | 
159 |         {panelState.status === "ready" && (
160 |           <ReadyLayout
161 |             profile={panelState.profile}
162 |             authorId={authorId}
163 |             scatterPoints={panelState.scatterPoints}
164 |           />
165 |         )}
166 |       </div>
167 |     </section>
168 |   );
169 | }
170 | 
171 | // ---------------------------------------------------------------------------
172 | // Sub-components (internal only)
173 | // ---------------------------------------------------------------------------
174 | 
175 | function LoadingSkeleton() {
176 |   return (
177 |     <div role="status" aria-live="polite" className="flex flex-col gap-4">
178 |       <p className="text-sm text-muted-foreground">{en.styleDna.loading}</p>
179 |       <div className="animate-pulse flex flex-col gap-2" aria-hidden="true">
180 |         <div className="h-3 w-1/3 rounded bg-muted" />
181 |         <div className="h-40 w-full rounded bg-muted" />
182 |         <div className="h-3 w-1/4 rounded bg-muted" />
183 |         <div className="h-40 w-full rounded bg-muted" />
184 |       </div>
185 |     </div>
186 |   );
187 | }
188 | 
189 | function ErrorNotice({
190 |   message,
191 |   onRetry,
192 | }: {
193 |   message: string;
194 |   onRetry: () => void;
195 | }) {
196 |   return (
197 |     <div
198 |       role="status"
199 |       aria-live="assertive"
200 |       className="flex flex-col items-start gap-3"
201 |     >
202 |       <p className="flex items-center gap-2 text-sm text-muted-foreground">
203 |         <TriangleAlert className="size-4 text-destructive" aria-hidden="true" />
204 |         {message}
205 |       </p>
206 |       <Button variant="outline" size="sm" onClick={onRetry}>
207 |         {en.styleDna.retry}
208 |       </Button>
209 |     </div>
210 |   );
211 | }
212 | 
213 | function ReadyLayout({
214 |   profile,
215 |   authorId,
216 |   scatterPoints,
217 | }: {
218 |   profile: StyleProfile;
219 |   authorId: string;
220 |   scatterPoints: ScatterAuthorPoint[];
221 | }) {
222 |   const dateStr = new Date(profile.computed_at).toLocaleDateString("en-US", {
223 |     year: "numeric",
224 |     month: "short",
225 |     day: "numeric",
226 |   });
227 | 
228 |   return (
229 |     <Card className="shadow-paper animate-fade-rise">
230 |       <CardContent className="flex flex-col gap-6 py-5">
231 |         {/* Chips row + computed_at caption */}
232 |         <div className="flex flex-wrap items-center justify-between gap-3">
233 |           <CorpusMetricChips {...profile.corpus_stats} />
234 |           <span className="font-mono text-xs text-muted-foreground">
235 |             {en.styleDna.computedAt(dateStr)}
236 |           </span>
237 |         </div>
238 | 
239 |         {/* Two-column grid: radar left, scatter right */}
240 |         <div className="grid gap-6 md:grid-cols-2">
241 |           {/* Radar */}
242 |           <div className="flex flex-col gap-2">
243 |             <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
244 |               {en.styleDna.radarSectionTitle}
245 |             </h3>
246 |             <StyleRadarChart profile={profile} authorId={authorId} />
247 |             <p className="text-xs text-muted-foreground">
248 |               {en.styleDna.radarCaption}
249 |             </p>
250 |           </div>
251 | 
252 |           {/* Scatter */}
253 |           <div className="flex flex-col gap-2">
254 |             <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
255 |               {en.styleDna.scatterSectionTitle}
256 |             </h3>
257 |             <StyleScatter2D points={scatterPoints} />
258 |           </div>
259 |         </div>
260 |       </CardContent>
261 |     </Card>
262 |   );
263 | }
264 | 
265 | // ---------------------------------------------------------------------------
266 | // Data-fetching helpers (pure async functions, not hooks — no lib layer exposure)
267 | // ---------------------------------------------------------------------------
268 | 
269 | /**
270 |  * Fetches a StyleProfile, falling back to the fixture on NETWORK failure only.
271 |  * A real 404 (NotFoundError) is re-thrown so the panel can show the empty state.
272 |  */
273 | async function fetchProfileWithFallback(
274 |   authorId: string,
275 | ): Promise<StyleProfile> {
276 |   try {
277 |     return await getStyleProfile(authorId);
278 |   } catch (err) {
279 |     // NotFoundError → empty state; re-throw
280 |     if (err instanceof NotFoundError) throw err;
281 |     // Network / 5xx → fall back to fixture if available; otherwise re-throw
282 |     const fixture = FIXTURE_STYLE_PROFILES[authorId];
283 |     if (fixture) {
284 |       console.info(
285 |         `[StyleDnaPanel] API unreachable — using fixture for "${authorId}" (demo-safe fallback)`,
286 |       );
287 |       return fixture;
288 |     }
289 |     throw err;
290 |   }
291 | }
292 | 
293 | /**
294 |  * Builds the scatter point array: the selected author + all other authors
295 |  * whose profiles are available (parallel fetch, silently skip failures).
296 |  */
297 | async function buildScatterPoints(
298 |   selectedAuthorId: string,
299 |   selectedAuthorName: string,
300 |   selectedProfile: StyleProfile,
301 | ): Promise<ScatterAuthorPoint[]> {
302 |   const points: ScatterAuthorPoint[] = [
303 |     {
304 |       authorId: selectedAuthorId,
305 |       authorName: selectedAuthorName,
306 |       point: selectedProfile.embedding_umap_2d.centroid,
307 |       spread: selectedProfile.embedding_umap_2d.spread,
308 |       selected: true,
309 |     },
310 |   ];
311 | 
312 |   // Fetch the author list to get other authors
313 |   let authorSummaries: { id: string; name: string }[] = [];
314 |   try {
315 |     authorSummaries = await listAuthors();
316 |   } catch {
317 |     // If author list fails, use known fixture authors as fallback
318 |     authorSummaries = Object.keys(FIXTURE_STYLE_PROFILES)
319 |       .filter((id) => id !== selectedAuthorId)
320 |       .map((id) => ({ id, name: id }));
321 |   }
322 | 
